#include <iomanip>
#include <iostream>

int main()
{
    std::array<int, 5> scores{};

    // Read the 5 values, then print the sum and the average.

    return 0;
}

solution_code:
#include <array>
#include <iomanip>
#include <iostream>

int main()
{
    std::array<int, 5> scores{};

    for (auto& s : scores)
        std::cin >> s;

    int sum{ 0 };
    for (auto s : scores)
        sum += s;

    double average{ static_cast<double>(sum) / static_cast<double>(scores.size()) };

    std::cout << sum << '\n';
    std::cout << std::fixed << std::setprecision(1) << average << '\n';

    return 0;
}

