solution_code:
#include <array>
#include <cstddef>
#include <iostream>

int main()
{
    std::array<int, 6> temps{};

    for (auto& t : temps)
        std::cin >> t;

    int threshold{};
    std::cin >> threshold;

    std::size_t count{ 0 };
    for (auto t : temps)
    {
        if (t > threshold)
            ++count;
    }

    std::cout << count << '\n';

    for (auto t : temps)
    {
        if (t > threshold)
            std::cout << t << '\n';
    }

    return 0;
}
